# %% [markdown]
# ## Calculate weather summary table

# %%
# parameters

daily_weather_params = dict()

# %%
# call the task


daily_weather = (
    summarize_df.set_task_instance_id("daily_weather")
    .handle_errors()
    .with_tracing()
    .skipif(
        conditions=[
            any_is_empty_df,
            any_dependency_skipped,
        ],
        unpack_depth=1,
    )
    .partial(
        df=df_with_temporal_index,
        groupby_cols=["weather_station", "date"],
        summary_params=[
            {
                "display_name": "precipitation",
                "aggregator": "sum",
                "column": "precipitation",
            },
            {
                "display_name": "temperature",
                "aggregator": "mean",
                "column": "temperature",
            },
            {
                "display_name": "wind_speed",
                "aggregator": "mean",
                "column": "wind_speed",
            },
            {"display_name": "wind_gusts", "aggregator": "max", "column": "wind_gusts"},
            {
                "display_name": "soil_temperature",
                "aggregator": "mean",
                "column": "soil_temperature",
            },
            {
                "display_name": "relative_humidity",
                "aggregator": "mean",
                "column": "relative_humidity",
            },
            {
                "display_name": "atmospheric_pressure",
                "aggregator": "mean",
                "column": "atmospheric_pressure",
            },
        ],
        reset_index=True,
        **daily_weather_params,
    )
    .call()
)


